namespace sv_4387867678af4e76910f2aed3d88f979.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds theme state for a single circuit.
/// Interactive components subscribe to <see cref="OnThemeChanged"/> to react
/// when any other component mutates the theme.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd"; // Bootstrap primary blue

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>
    /// Raised whenever <see cref="Theme"/> or <see cref="AccentColor"/> changes.
    /// Subscribers must call <c>InvokeAsync(StateHasChanged)</c> to re-render.
    /// </summary>
    public event Action? OnThemeChanged;

    /// <summary>
    /// Applies both values at once, raising a single notification.
    /// </summary>
    public void SetPreferences(ThemeMode theme, string accentColor)
    {
        bool changed = _theme != theme || _accentColor != accentColor;
        _theme = theme;
        _accentColor = accentColor;
        if (changed) NotifyChanged();
    }

    private void NotifyChanged() => OnThemeChanged?.Invoke();
}

@implements IDisposable
@inject ThemeService ThemeService

<span class="badge rounded-pill" style="background-color: @ThemeService.AccentColor; color: white;">
    @GetIcon() @ThemeService.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetIcon() => ThemeService.Theme switch
    {
        ThemeMode.Light  => "☀️",
        ThemeMode.Dark   => "🌙",
        ThemeMode.System => "💻",
        _                => "🎨"
    };

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

@implements IDisposable
@inject ThemeService ThemeService

<div class="p-3">
    <label class="form-label fw-semibold">Theme</label>
    <div class="btn-group d-flex" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            var isActive = ThemeService.Theme == mode;
            <button type="button"
                    class="btn @(isActive ? "btn-primary" : "btn-outline-secondary") btn-sm"
                    style="@(isActive ? $"background-color:{ThemeService.AccentColor};border-color:{ThemeService.AccentColor};" : "")"
                    @onclick="() => ThemeService.Theme = mode">
                @mode
            </button>
        }
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card" style="max-width: 480px; border-color: @ThemeService.AccentColor;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@ThemeService.Theme"
                    @onchange="OnThemeModeChanged">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    <option value="@mode">@mode</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@ThemeService.AccentColor"
                       @onchange="OnAccentColorChanged" />
                <code>@ThemeService.AccentColor</code>
            </div>
        </div>

        <div class="alert alert-info mb-0">
            Current: <strong>@ThemeService.Theme</strong> mode,
            accent <span class="badge" style="background-color:@ThemeService.AccentColor;">@ThemeService.AccentColor</span>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnThemeChanged += HandleThemeChanged;
    }

    private void OnThemeModeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<ThemeMode>(e.Value?.ToString(), out var mode))
        {
            ThemeService.Theme = mode;
        }
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? ThemeService.AccentColor;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnThemeChanged -= HandleThemeChanged;
    }
}

